module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

    reg [3:0] cnt_10;
    reg [6:0] cnt_100;

    initial begin
        cnt_10 = 4'b0000;
        cnt_100 = 7'b0000000;
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_50 <= 1'b0;
        end else begin
            CLK_50 <= ~CLK_50;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_10 <= 1'b0;
            cnt_10 <= 4'b0000;
        end else begin
            if (cnt_10 == 4'b1001) begin
                CLK_10 <= ~CLK_10;
                cnt_10 <= 4'b0000;
            end else begin
                cnt_10 <= cnt_10 + 1;
            end
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_1 <= 1'b0;
            cnt_100 <= 7'b0000000;
        end else begin
            if (cnt_100 == 7'b1100011) begin
                CLK_1 <= ~CLK_1;
                cnt_100 <= 7'b0000000;
            end else begin
                cnt_100 <= cnt_100 + 1;
            end
        end
    end

endmodule
